ALTER PROCEDURE [dbo].[ACC_sp_CallDocNumber] @Err_x INT OUTPUT, @TransId NVARCHAR(10), @Company NVARCHAR(10), @Loca NVARCHAR(10) AS BEGIN SET NOCOUNT ON; BEGIN TRAN IF (@TransId = 'EBTDN') BEGIN DECLARE @T_B_N NVARCHAR(20); SET @T_B_N = (SELECT Temp_Bill_No FROM ACC_GetSystem_DoctNo WHERE Com_Code = @Company); SET @T_B_N = LTRIM(RTRIM(REPLICATE('0',(7-LEN(@T_B_N)))))+LTRIM(RTRIM(@T_B_N)); SELECT 'EBN' + @Company + @T_B_N [Temp_Bill_No]; SELECT Code, Cust_Name FROM ACC_Customer WHERE Locked='0' ORDER BY Code; SELECT Code, Prod_Name FROM ACC_Product ORDER BY Code; UPDATE ACC_GetSystem_DoctNo SET Temp_Bill_No = Temp_Bill_No + 1 WHERE Com_Code = @Company; GOTO TransEnd END ELSE IF (@TransId = 'ADVPY') BEGIN DECLARE @T_A_N NVARCHAR(20); SET @T_A_N = (SELECT Temp_AdvPy_No FROM ACC_GetSystem_DoctNo WHERE Com_Code = @Company); SET @T_A_N = LTRIM(RTRIM(REPLICATE('0',(7-LEN(@T_A_N))))) + LTRIM(RTRIM(@T_A_N)); SELECT 'ADP' + @Company + @T_A_N [Temp_AdvPy_No]; UPDATE ACC_GetSystem_DoctNo SET Temp_AdvPy_No = Temp_AdvPy_No + 1 WHERE Com_Code = @Company; GOTO TransEnd END ELSE IF (@TransId = 'WRCHQ') BEGIN DECLARE @WRCHQ NVARCHAR(20); SET @WRCHQ = (SELECT Temp_WrChq FROM ACC_GetSystem_DoctNo WHERE Com_Code = @Company); SET @WRCHQ = LTRIM(RTRIM(REPLICATE('0',(7-LEN(@WRCHQ)))))+LTRIM(RTRIM(@WRCHQ)); SELECT 'WCH' + @Company + @WRCHQ [Temp_WrChq]; SELECT Code,Cust_Name FROM ACC_Customer WHERE Locked='0' ORDER BY Code; SELECT Sub_Code,Sub_Acc_Name FROM Acc_Sub_Accounts WHERE Main_Acc_Code = '400' OR Sub_Code LIKE '112%' OR Main_Acc_Code = '13000' ORDER BY Sub_Code; UPDATE ACC_GetSystem_DoctNo SET Temp_WrChq = Temp_WrChq + 1 WHERE Com_Code = @Company; GOTO TransEnd END TransEnd: COMMIT TRAN RETURN Problem: IF (@@TRANCOUNT > 0) ROLLBACK TRAN END
